// Custom Worker entrypoint (wrangler.jsonc "main"): wraps the OpenNext
// fetch handler and adds the poller's scheduled + queue handlers — the
// documented @opennextjs/cloudflare pattern for non-fetch events.
// @ts-ignore — generated by `opennextjs-cloudflare build`, absent while the
// inner `next build` typechecks (the adapter wipes .open-next first).
import openNextHandlerModule from "../.open-next/worker.js";

const openNextHandler = openNextHandlerModule as ExportedHandler<CloudflareEnv>;
// Side effect: populates the connector registry (one line per vendor).
import "./connectors";
import { createDb } from "./db/client";
import type { CredentialEnv } from "./lib/credentials";
import type { EmailEnv } from "./lib/email";
import {
  resolvePaddleServerConfig,
  type PaddleEnv,
  type PaddleServerConfig,
} from "./lib/paddle";
import { listOrgIds, listSubscriptionsToMeter } from "./db/system";
import { SYSTEM_ORG_ID, type PollMessage } from "./poller/messages";
import { processPollMessage } from "./poller/process";
import { sendInBatches } from "./poller/queue";
import { retryDelaySeconds, RetryableConnectorError } from "./poller/run";
import { previousDay } from "./scoring";
import { resolveRedirect } from "./lib/domains";
import { parseAdminUserIds, type AdminEnv } from "./lib/admin-access";
import {
  digestReturnDim,
  isCompanionRevisit,
  isLandingPageView,
  writeLaunchEvent,
} from "./lib/launch-events";
import {
  createRequestTimingStore,
  formatServerTiming,
  runWithRequestTiming,
} from "./lib/request-timing";

// Matches the second entry in wrangler.jsonc "triggers".crons — the nightly
// score recompute (W1-F). The */5 tick keeps the W0-B heartbeat + purge.
const NIGHTLY_SCORE_CRON = "0 2 * * *";
// Daily seat metering (W3-M PR5): one message per active/trialing subscription.
const METERING_CRON = "0 3 * * *";
// Weekly digest (F2.2): Monday 14:00 UTC (a humane send hour) — one message per
// org, fanned out through the existing revealyst-poll queue.
const DIGEST_CRON = "0 14 * * 1";
// Weekly §14 flywheel report (W5-I): Monday 15:00 UTC (after the digest fan-out)
// — ONE system message emailing the platform admins the adoption funnel.
const FLYWHEEL_CRON = "0 15 * * 1";
// Monthly executive memo (W6-F): 1st of month, 16:00 UTC — one message per org,
// fanned out through the existing poll queue. The memo reports the month that
// just ended (the consumer anchors its reads at yesterday). Matches the sixth
// wrangler.jsonc "triggers".crons entry.
const MONTHLY_EXEC_CRON = "0 16 1 * *";

/** Paddle server config for the consumer, or undefined when unconfigured —
 * resolved safely so a missing key never breaks non-metering queue work. */
function safePaddleConfig(env: CloudflareEnv): PaddleServerConfig | undefined {
  try {
    return resolvePaddleServerConfig(env as unknown as PaddleEnv);
  } catch {
    return undefined;
  }
}

// Dead-letter queue for poll messages that exhaust max_retries (wrangler.jsonc
// consumer config). This worker consumes it too — see the queue() branch.
const DLQ_QUEUE_NAME = "revealyst-poll-dlq";

export default {
  // Host split (src/lib/domains.ts): keep each custom domain to its own
  // surface — app paths land on app.revealyst.com, marketing paths on
  // revealyst.com — and move legacy-host (workers.dev) pages to their
  // canonical home, before handing off to OpenNext. Only GET/HEAD page
  // requests ever redirect; /api/*, assets, neutral metadata routes, the
  // OpenNext self-reference subrequest, and unknown hosts (localhost, CI
  // previews) pass straight through.
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const target = resolveRedirect(
      url.hostname,
      request.method,
      url.pathname,
      url.search,
    );
    if (target) return Response.redirect(target, 308);

    const accept = request.headers.get("accept") ?? "";
    const isRsc = request.headers.has("rsc");

    // §15 landing_view — fired at this seam, not in the page render: the
    // landing page is now a build-time prerender (perf/edge-caching), so the
    // old per-request in-render write can't exist. Firing AFTER the host-split
    // 308 means an `/` request that redirects to its canonical host is never
    // counted here (it renders on the marketing host, where it's counted).
    // isLandingPageView keeps the OLD crawler-inclusive series — every
    // GET/HEAD of `/` regardless of Accept, RSC soft-navs excluded (see its
    // doc) — and, unlike a client beacon, can't be dropped by content
    // blockers. Two accepted deltas vs. the in-render write, both toward
    // over- not under-counting: (1) it fires before the render, so an `/`
    // request whose render later 500s is still counted (the old write, being
    // the render's first line, effectively counted these too); (2) it counts
    // HEAD `/`. writeLaunchEvent never throws and no-ops without the binding.
    if (isLandingPageView(request.method, url.pathname, isRsc)) {
      writeLaunchEvent(env.LAUNCH_EVENTS, "landing_view", undefined, url.hostname);
    }

    // §14 flywheel instrumentation (W5-I), fired at this same edge seam (after
    // the host-split 308, so each counts only on its canonical host) and, like
    // landing_view, immune to content blockers and free of any page-render cost:
    //  - digest_return: a click-through from a weekly-digest CTA (?src=digest),
    //    dim = the coarse ISO week the digest was sent.
    //  - companion_revisit: a full-document view of the companion surface
    //    (/dashboard) — the returning-engagement signal, no identity attached.
    const digestDim = digestReturnDim(
      request.method,
      isRsc,
      url.searchParams.get("src"),
      url.searchParams.get("wk"),
    );
    if (digestDim !== null) {
      writeLaunchEvent(env.LAUNCH_EVENTS, "digest_return", digestDim, url.hostname);
    }
    if (isCompanionRevisit(request.method, url.pathname, isRsc)) {
      writeLaunchEvent(env.LAUNCH_EVENTS, "companion_revisit", undefined, url.hostname);
    }

    // Request-lifecycle instrumentation (incident: authenticated pages >7s
    // in prod). One AsyncLocalStorage store per instrumented request, entered
    // here (the outermost seam) so every `timeStage` call nested anywhere
    // downstream — api-context.ts, the (app) layout, dashboard/page.tsx, the
    // opt-in db probe — shares one collector, however deep the RSC render
    // goes. Server-Timing is standard and low-risk: stage names + ms
    // durations only, no query text/user data.
    //
    // Instrument only documents, /api/*, /v1/* (the OTel receiver — V1-001),
    // and RSC soft-navigations (Next sends an `RSC` header with
    // `Accept: */*` on client-side nav — the dominant way returning users
    // reach slow pages). Assets and anything else pass through UNTOUCHED: no
    // ALS wrap, no header clone, no Response reconstruction — which also
    // keeps 101/WebSocket upgrade responses intact (a reconstructed Response
    // drops the webSocket pair).
    const instrument =
      accept.includes("text/html") ||
      url.pathname.startsWith("/api/") ||
      url.pathname.startsWith("/v1/") ||
      isRsc;
    if (!instrument) {
      return openNextHandler.fetch!(request, env, ctx);
    }

    const store = createRequestTimingStore(url.pathname);
    const response = await runWithRequestTiming(store, () =>
      openNextHandler.fetch!(request, env, ctx),
    );
    // Defense in depth: never reconstruct an upgrade response (the WHATWG
    // Response constructor can't carry Cloudflare's webSocket pair).
    if (
      response.status === 101 ||
      (response as Response & { webSocket?: unknown }).webSocket
    ) {
      return response;
    }

    // `store.start` is the single source of truth for the total — the same
    // clock `timeStage` records against.
    const total = Date.now() - store.start;
    const responseHeaders = new Headers(response.headers);
    responseHeaders.append(
      "Server-Timing",
      formatServerTiming(store.stages, total),
    );
    // Summary line for wrangler tail / Workers Logs. For streamed pages
    // (routes with loading.tsx), stages inside a Suspense boundary resolve
    // AFTER this point — `store.flushed` makes `timeStage` log those late
    // stages individually, so the heaviest stage of a slow page is never
    // silently dropped from the logs (the header can't be amended after
    // flush; that's fundamental to HTTP).
    console.log(
      JSON.stringify({ path: url.pathname, total, stages: store.stages }),
    );
    store.flushed = true;

    return new Response(response.body, {
      status: response.status,
      statusText: response.statusText,
      headers: responseHeaders,
    });
  },

  // Cron Trigger (every 5 min): heartbeat + raw purge (W0-B/C), then W1-D
  // connector dispatch — one queue message per due connection (regular
  // polls when the vendor interval elapsed; the chunked backfill
  // chain-start once per new connection).
  async scheduled(controller, env) {
    if (controller.cron === NIGHTLY_SCORE_CRON) {
      // Nightly score recompute: one queue message per org, anchored at
      // yesterday UTC (the last fully-ingested day). Batched sends — the
      // fan-out must not serialize thousands of orgs one send at a time.
      const db = createDb(env);
      const day = previousDay(new Date().toISOString().slice(0, 10));
      const messages = (await listOrgIds(db)).map(
        (orgId) =>
          ({ kind: "score-recompute", orgId, day }) satisfies PollMessage,
      );
      await sendInBatches(env.POLL_QUEUE, messages);
      // W4-Q: once-nightly retention purge of audit_log / poll_heartbeats /
      // connector_runs (bounded batches inside the consumer). One system-level
      // message, riding the same nightly tick as the score recompute.
      await env.POLL_QUEUE.send({
        kind: "purge-retention",
      } satisfies PollMessage);
      return;
    }
    if (controller.cron === METERING_CRON) {
      // Daily seat metering: one message per active/trialing subscription. The
      // consumer no-ops when the tracked_user count is unchanged.
      if (!safePaddleConfig(env)) {
        // Paddle isn't configured here — don't enqueue messages that would just
        // dead-letter in the consumer every day. (No active subs exist without
        // Paddle configured anyway; this is belt-and-suspenders.)
        console.error("[meter] skipped: Paddle is not configured");
        return;
      }
      const db = createDb(env);
      const messages = (await listSubscriptionsToMeter(db)).map(
        (s) =>
          ({
            kind: "meter-subscription",
            orgId: s.orgId,
            paddleSubscriptionId: s.paddleSubscriptionId,
            priceId: s.priceId,
          }) satisfies PollMessage,
      );
      await sendInBatches(env.POLL_QUEUE, messages);
      return;
    }
    if (controller.cron === DIGEST_CRON) {
      // Weekly digest fan-out: one message per org onto the existing poll queue.
      // Messages stay tiny (org id only); all assembly/staleness/idempotency
      // work happens in the consumer (src/poller/digest.ts).
      const db = createDb(env);
      const messages = (await listOrgIds(db)).map(
        (orgId) => ({ kind: "digest-weekly", orgId }) satisfies PollMessage,
      );
      await sendInBatches(env.POLL_QUEUE, messages);
      return;
    }
    if (controller.cron === FLYWHEEL_CRON) {
      // Weekly §14 flywheel report: ONE system-level message (not per org) —
      // the consumer reads the cross-org funnel and emails platform admins.
      await env.POLL_QUEUE.send({ kind: "flywheel-report" } satisfies PollMessage);
      return;
    }
    if (controller.cron === MONTHLY_EXEC_CRON) {
      // Monthly executive memo fan-out: one message per org onto the existing
      // poll queue (org id only; all compose/idempotency work is in the
      // consumer, src/poller/exec-report.ts). Reports the month that just ended.
      const db = createDb(env);
      const messages = (await listOrgIds(db)).map(
        (orgId) => ({ kind: "exec-report-monthly", orgId }) satisfies PollMessage,
      );
      await sendInBatches(env.POLL_QUEUE, messages);
      return;
    }
    // Heartbeat + raw-payload purge on the */5 tick. Connector polling was
    // REMOVED with the pivot to the desktop-agent usage-source model (ADR
    // 0056): the registry ships empty and usage now arrives via the device
    // push path (/api/agent/ingest, /v1/metrics), so there is no per-connection
    // poll to dispatch. Existing connector rows are frozen in place — they
    // simply receive no new data.
    await env.POLL_QUEUE.send({
      kind: "noop-poll",
      orgId: SYSTEM_ORG_ID,
    } satisfies PollMessage);
    await env.POLL_QUEUE.send({ kind: "purge-raw" } satisfies PollMessage);
  },

  async queue(batch, env) {
    if (batch.queue === DLQ_QUEUE_NAME) {
      // A poll message that exhausted all retries. It can't be recovered
      // here, but it must not vanish silently: log the full body at error
      // level (Workers Logs / Logpush make it durable + alertable) and ack
      // so it doesn't loop back into the DLQ.
      for (const message of batch.messages) {
        console.error(
          `[dlq] message dead-lettered after ${message.attempts} attempts:`,
          JSON.stringify(message.body),
        );
        message.ack();
      }
      return;
    }
    const db = createDb(env);
    const paddleConfig = safePaddleConfig(env);
    for (const message of batch.messages) {
      try {
        await processPollMessage(db, message.body, {
          credentialEnv: env as unknown as CredentialEnv,
          emailEnv: env as unknown as EmailEnv,
          appOrigin: (env as unknown as { BETTER_AUTH_URL?: string }).BETTER_AUTH_URL ?? "",
          adminUserIds: parseAdminUserIds(env as unknown as AdminEnv),
          send: async (m, opts) => {
            await env.POLL_QUEUE.send(
              m,
              opts?.delaySeconds ? { delaySeconds: opts.delaySeconds } : undefined,
            );
          },
          attempt: message.attempts,
          paddleConfig,
        });
        message.ack();
      } catch (error) {
        // Permanent connector failures are recorded on the run/connection
        // inside the handler and never reach here; what does is retryable:
        // vendor 429/5xx (with its own delay) or an unexpected crash
        // (default queue backoff). The consumer's max_retries (set
        // explicitly in wrangler.jsonc) bounds redelivery; always log —
        // a message dropped after its last retry must not vanish silently.
        console.error(
          `[queue] ${message.body.kind} attempt ${message.attempts} failed:`,
          error,
        );
        if (error instanceof RetryableConnectorError) {
          message.retry({
            delaySeconds: Math.max(
              error.delaySeconds,
              retryDelaySeconds(message.attempts),
            ),
          });
        } else {
          message.retry();
        }
      }
    }
  },
} satisfies ExportedHandler<CloudflareEnv, PollMessage>;
